def calculateStatistics(json_data):
    import json
    from statistics import mean, median, mode

    try:
        # Parse JSON data
        data = json.loads(json_data)

        # Extract scores, ensuring they are numeric
        scores = []
        for item in data:
            try:
                score = float(item) if isinstance(item, (int, float, str)) else None
                if score is not None:
                    scores.append(score)
            except (ValueError, TypeError):
                continue

        if not scores:
            return {"error": "No valid numeric scores found in the input data"}

        # Calculate statistics
        result = {
            "mean": mean(scores),
            "median": median(scores),
            "mode": mode(scores) if len(set(scores)) < len(scores) else scores[0]
        }

        return result

    except json.JSONDecodeError:
        return {"error": "Invalid JSON format"}
    except Exception as e:
        return {"error": f"An error occurred: {str(e)}"}
