public class TrafficOptimizer {

    public static Map<Integer, List<Integer>> trafficOptimizer(Graph cityGraph) {
        Map<Integer, List<Integer>> optimizedPaths = new HashMap<>();
        PriorityQueue<Node> queue = new PriorityQueue<>(Comparator.comparingDouble(n -> n.trafficDensity));
        Map<Integer, Double> bestTraffic = new HashMap<>();
        Map<Integer, List<Integer>> bestPaths = new HashMap<>();

        // Initialize all vertices with infinity traffic density
        for (Vertex v : cityGraph.getVertices()) {
            bestTraffic.put(v.getId(), Double.MAX_VALUE);
            bestPaths.put(v.getId(), new ArrayList<>());
        }

        // For each starting point (intersection)
        for (Vertex start : cityGraph.getVertices()) {
            int startId = start.getId();

            // Reset for new starting point
            queue.clear();
            for (Integer vId : bestTraffic.keySet()) {
                bestTraffic.put(vId, Double.MAX_VALUE);
                bestPaths.put(vId, new ArrayList<>());
            }

            // Set starting point
            bestTraffic.put(startId, 0.0);
            queue.add(new Node(startId, 0.0));
            List<Integer> startPath = new ArrayList<>();
            startPath.add(startId);
            bestPaths.put(startId, startPath);

            // Dijkstra's algorithm with traffic density as edge weight
            while (!queue.isEmpty()) {
                Node current = queue.poll();
                int currentId = current.vertex;

                if (current.trafficDensity > bestTraffic.get(currentId)) {
                    continue;
                }

                // Check all adjacent vertices
                for (Edge e : cityGraph.getEdgesFrom(currentId)) {
                    int neighborId = e.getDestination();
                    double newTraffic = bestTraffic.get(currentId) + e.getTrafficDensity();

                    if (newTraffic < bestTraffic.get(neighborId)) {
                        bestTraffic.put(neighborId, newTraffic);

                        // Update path
                        List<Integer> newPath = new ArrayList<>(bestPaths.get(currentId));
                        newPath.add(neighborId);
                        bestPaths.put(neighborId, newPath);

                        // Add to queue for further exploration
                        queue.add(new Node(neighborId, newTraffic));
                    }
                }
            }

            // Store optimized paths from this starting point
            Map<Integer, List<Integer>> pathsFromStart = new HashMap<>();
            for (Integer destination : bestPaths.keySet()) {
                if (destination != startId && !bestPaths.get(destination).isEmpty()) {
                    pathsFromStart.put(destination, bestPaths.get(destination));
                }
            }
            optimizedPaths.put(startId, pathsFromStart);
        }

        return optimizedPaths;
    }

    private static class Node {
        int vertex;
        double trafficDensity;

        public Node(int vertex, double trafficDensity) {
            this.vertex = vertex;
            this.trafficDensity = trafficDensity;
        }
    }
}

