    is_occupied: bool,
    flight_number: Option<String>,
}

enum ActionType {
    Allocate,
    Deallocate,
    Status,
}

struct GateAction {
    action_type: ActionType,
    gate_id: String,
    flight_number: Option<String>,
}

struct AirportGates {
    gates: Vec<Gate>,
}

impl AirportGates {
    fn new() -> Self {
        AirportGates { gates: Vec::new() }
    }

    fn add_gate(&mut self, gate_id: String) {
        self.gates.push(Gate {
            id: gate_id,
            is_occupied: false,
            flight_number: None,
        });
    }

    fn manage_airport_gates(&mut self, action: GateAction) -> Result<String, String> {
        match action.action_type {
            ActionType::Allocate => self.allocate_gate(action.gate_id, action.flight_number),
            ActionType::Deallocate => self.deallocate_gate(action.gate_id),
            ActionType::Status => self.check_gate_status(action.gate_id),
        }
    }

    fn allocate_gate(&mut self, gate_id: String, flight_number: Option<String>) -> Result<String, String> {
        for gate in &mut self.gates {
            if gate.id == gate_id {
                if gate.is_occupied {
                    return Err(format!("Gate {} is already occupied", gate_id));
                }
                gate.is_occupied = true;
                gate.flight_number = flight_number.clone();
                return Ok(format!("Gate {} allocated successfully to flight {:?}", gate_id, flight_number));
            }
        }
        Err(format!("Gate {} not found", gate_id))
    }

    fn deallocate_gate(&mut self, gate_id: String) -> Result<String, String> {
        for gate in &mut self.gates {
            if gate.id == gate_id {
                if !gate.is_occupied {
                    return Err(format!("Gate {} is already free", gate_id));
                }
                gate.is_occupied = false;
                let flight_number = gate.flight_number.clone();
                gate.flight_number = None;
                return Ok(format!("Gate {} deallocated successfully from flight {:?}", gate_id, flight_number));
            }
        }
        Err(format!("Gate {} not found", gate_id))
    }

    fn check_gate_status(&self, gate_id: String) -> Result<String, String> {
        for gate in &self.gates {
            if gate.id == gate_id {
                let status = if gate.is_occupied {
                    format!("occupied by flight {:?}", gate.flight_number)
                } else {
                    "free".to_string()
                };
                return Ok(format!("Gate {} is {}", gate_id, status));
            }
        }
        Err(format!("Gate {} not found", gate_id))
    }
}

fn manage_airport_gates(airport: &mut AirportGates, action: GateAction) -> Result<String, String> {
    airport.manage_airport_gates(action)
