    OperationType type;
    std::string permissionPath;
    bool value;  // For ADD/UPDATE operations
};

bool applyOperation(PermissionTree& node, const std::string& path, 
                   const OperationType& type, bool value) {
    size_t pos = path.find('/');
    std::string current = (pos == std::string::npos) ? path : path.substr(0, pos);
    std::string remaining = (pos == std::string::npos) ? "" : path.substr(pos + 1);

    if (current == node->name) {
        if (remaining.empty()) {
            // Target node found
            switch (type) {
                case OperationType::ADD:
                    // Node already exists, can't add
                    return false;
                case OperationType::UPDATE:
                    node->isGranted = value;
                    return true;
                case OperationType::REMOVE:
                    // Can't remove root node
                    return false;
            }
        }

        // Continue traversing
        size_t nextSlash = remaining.find('/');
        std::string nextNode = (nextSlash == std::string::npos) ? remaining : remaining.substr(0, nextSlash);

        for (auto& child : node->children) {
            if (child->name == nextNode) {
                return applyOperation(child, remaining, type, value);
            }
        }

        // Child not found
        if (type == OperationType::ADD) {
            // Create the path
            std::shared_ptr<PermissionNode> newNode = std::make_shared<PermissionNode>(nextNode);
            node->addChild(newNode);
            if (remaining == nextNode) {
                newNode->isGranted = value;
                return true;
            } else {
                return applyOperation(newNode, remaining, type, value);
            }
        }
    }

    return false;
}

PermissionTree managePermissions(PermissionTree permissionTree, const std::vector<Operation>& operations) {
    if (!permissionTree) {
        return nullptr;
    }

    for (const auto& op : operations) {
        applyOperation(permissionTree, op.permissionPath, op.type, op.value);
    }

    return permissionTree;
}
