    AddNode { parent_id: String, node: NetworkNode },
    UpdateNode { id: String, name: Option<String>, ip: Option<String>, subnet: Option<String>, properties: Option<HashMap<String, String>> },
    RemoveNode { id: String },
    GetNode { id: String },
}

struct NetworkTree {
    root: NetworkNode,
}

impl NetworkTree {
    fn new(root_node: NetworkNode) -> Self {
        NetworkTree { root: root_node }
    }

    fn find_node_mut(&mut self, id: &str) -> Option<&mut NetworkNode> {
        self.find_node_mut_recursive(&mut self.root, id)
    }

    fn find_node_mut_recursive(&mut self, current: &mut NetworkNode, id: &str) -> Option<&mut NetworkNode> {
        if current.id == id {
            return Some(current);
        }

        for (_, child) in current.children.iter_mut() {
            if let Some(node) = self.find_node_mut_recursive(child, id) {
                return Some(node);
            }
        }

        None
    }

    fn find_node(&self, id: &str) -> Option<&NetworkNode> {
        self.find_node_recursive(&self.root, id)
    }

    fn find_node_recursive<'a>(&self, current: &'a NetworkNode, id: &str) -> Option<&'a NetworkNode> {
        if current.id == id {
            return Some(current);
        }

        for (_, child) in current.children.iter() {
            if let Some(node) = self.find_node_recursive(child, id) {
                return Some(node);
            }
        }

        None
    }
}

fn manageNetworkConfig(tree: &mut NetworkTree, action: NetworkAction) -> Result<Option<&NetworkNode>, String> {
    match action {
        NetworkAction::AddNode { parent_id, node } => {
            let parent = tree.find_node_mut(&parent_id)
                .ok_or_else(|| format!("Parent node with ID {} not found", parent_id))?;

            let node_id = node.id.clone();
            if parent.children.contains_key(&node_id) {
                return Err(format!("Node with ID {} already exists under parent {}", node_id, parent_id));
            }

            parent.children.insert(node_id, node);
            Ok(None)
        },
        NetworkAction::UpdateNode { id, name, ip, subnet, properties } => {
            let node = tree.find_node_mut(&id)
                .ok_or_else(|| format!("Node with ID {} not found", id))?;

            if let Some(new_name) = name {
                node.name = new_name;
            }

            if let Some(new_ip) = ip {
                node.ip_address = Some(new_ip);
            }

            if let Some(new_subnet) = subnet {
                node.subnet_mask = Some(new_subnet);
            }

            if let Some(new_props) = properties {
                for (key, value) in new_props {
                    node.properties.insert(key, value);
                }
            }

            Ok(None)
        },
        NetworkAction::RemoveNode { id } => {
            // First, find the parent node
            let mut parent_id = None;
            let mut child_id = None;

            fn find_parent(current: &NetworkNode, target_id: &str) -> Option<(String, String)> {
                for (cid, child) in &current.children {
                    if child.id == target_id {
                        return Some((current.id.clone(), cid.clone()));
                    }

                    if let Some(result) = find_parent(child, target_id) {
                        return Some(result);
                    }
                }
                None
            }

            if id == tree.root.id {
                return Err("Cannot remove the root node".to_string());
            }

            if let Some((pid, cid)) = find_parent(&tree.root, &id) {
                parent_id = Some(pid);
                child_id = Some(cid);
            } else {
                return Err(format!("Node with ID {} not found", id));
            }

            if let (Some(pid), Some(cid)) = (parent_id, child_id) {
                let parent = tree.find_node_mut(&pid)
                    .ok_or_else(|| format!("Parent node with ID {} not found", pid))?;

                parent.children.remove(&cid);
            }

            Ok(None)
        },
        NetworkAction::GetNode { id } => {
            let node = tree.find_node(&id)
                .ok_or_else(|| format!("Node with ID {} not found", id))?;

            Ok(Some(node))
        }
    }
}
