public class FileSystemSimulator {
    private Map<String, Folder> folderMap = new HashMap<>();
    private Folder root;

    public FileSystemSimulator() {
        root = new Folder("root", null);
        folderMap.put("root", root);
    }

    public String fs_simulator(JSONObject input) throws JSONException {
        String action = input.getString("action");

        switch (action) {
            case "add":
                String folderName = input.getString("folderName");
                String parentFolderName = input.getString("parentFolderName");
                return addFolder(folderName, parentFolderName);

            case "move":
                String moveFolderName = input.getString("folderName");
                String newParentFolderName = input.getString("newParentFolderName");
                return moveFolder(moveFolderName, newParentFolderName);

            case "remove":
                String removeFolderName = input.getString("folderName");
                return removeFolder(removeFolderName);

            case "fetchPath":
                String fetchFolderName = input.getString("folderName");
                return getPath(fetchFolderName);

            default:
                return "Invalid action specified";
        }
    }

    private String addFolder(String folderName, String parentFolderName) {
        if (folderMap.containsKey(folderName)) {
            return "Error: Folder with name '" + folderName + "' already exists";
        }

        Folder parentFolder = folderMap.get(parentFolderName);
        if (parentFolder == null) {
            return "Error: Parent folder '" + parentFolderName + "' not found";
        }

        Folder newFolder = new Folder(folderName, parentFolder);
        parentFolder.addChild(newFolder);
        folderMap.put(folderName, newFolder);

        return "Folder '" + folderName + "' added to '" + parentFolderName + "'";
    }

    private String moveFolder(String folderName, String newParentFolderName) {
        Folder folder = folderMap.get(folderName);
        if (folder == null) {
            return "Error: Folder '" + folderName + "' not found";
        }

        if (folderName.equals("root")) {
            return "Error: Cannot move root folder";
        }

        Folder newParentFolder = folderMap.get(newParentFolderName);
        if (newParentFolder == null) {
            return "Error: New parent folder '" + newParentFolderName + "' not found";
        }

        // Check if new parent is a descendant of the folder to move (which would create a cycle)
        Folder current = newParentFolder;
        while (current != null) {
            if (current == folder) {
                return "Error: Cannot move folder to its own descendant";
            }
            current = current.getParent();
        }

        // Remove from old parent
        folder.getParent().removeChild(folder);

        // Add to new parent
        folder.setParent(newParentFolder);
        newParentFolder.addChild(folder);

        return "Folder '" + folderName + "' moved to '" + newParentFolderName + "'";
    }

    private String removeFolder(String folderName) {
        if (folderName.equals("root")) {
            return "Error: Cannot remove root folder";
        }

        Folder folder = folderMap.get(folderName);
        if (folder == null) {
            return "Error: Folder '" + folderName + "' not found";
        }

        // Remove all references to this folder and its descendants
        removeAllReferences(folder);

        // Remove from parent
        folder.getParent().removeChild(folder);

        return "Folder '" + folderName + "' removed";
    }

    private void removeAllReferences(Folder folder) {
        // Remove from folderMap
        folderMap.remove(folder.getName());

        // Recursively remove all children
        for (Folder child : new ArrayList<>(folder.getChildren())) {
            removeAllReferences(child);
        }
    }

    private String getPath(String folderName) {
        Folder folder = folderMap.get(folderName);
        if (folder == null) {
            return "Error: Folder '" + folderName + "' not found";
        }

        StringBuilder path = new StringBuilder();
        Folder current = folder;

        while (current != null) {
            path.insert(0, current.getName());
            if (current.getParent() != null) {
                path.insert(0, "/");
            }
            current = current.getParent();
        }

        return path.toString();
    }

    private class Folder {
        private String name;
        private Folder parent;
        private List<Folder> children;

        public Folder(String name, Folder parent) {
            this.name = name;
            this.parent = parent;
            this.children = new ArrayList<>();
        }

        public String getName() {
            return name;
        }

        public Folder getParent() {
            return parent;
        }

        public void setParent(Folder parent) {
            this.parent = parent;
        }

        public List<Folder> getChildren() {
            return children;
        }

        public void addChild(Folder child) {
            children.add(child);
        }

        public void removeChild(Folder child) {
            children.remove(child);
        }
    }
}
