def generateConfigTree(parameters):
    config_tree = {}

    # Set base configuration
    if 'hostname' in parameters:
        config_tree['hostname'] = parameters['hostname']

    # Set interfaces configuration
    if 'interfaces' in parameters:
        config_tree['interfaces'] = {}
        for interface_name, interface_config in parameters['interfaces'].items():
            config_tree['interfaces'][interface_name] = interface_config

    # Set routing protocols
    if 'routing' in parameters:
        config_tree['routing'] = {}
        for protocol, protocol_config in parameters['routing'].items():
            config_tree['routing'][protocol] = protocol_config

    # Set additional parameters
    for key, value in parameters.items():
        if key not in ['hostname', 'interfaces', 'routing']:
            config_tree[key] = value

    return config_tree

def get_config_value(config_tree, key_path):
    """Retrieve a value from the config tree based on key path"""
    current = config_tree
    for key in key_path:
        if key in current:
            current = current[key]
        else:
            return None
    return current

def set_config_value(config_tree, key_path, value):
    """Set a value in the config tree based on key path"""
    current = config_tree
    for key in key_path[:-1]:
        if key not in current:
            current[key] = {}
        current = current[key]
    current[key_path[-1]] = value
    return config_tree

def add_route(config_tree, protocol, route_config):
    """Add a new route to the routing section"""
    if 'routing' not in config_tree:
        config_tree['routing'] = {}
    if protocol not in config_tree['routing']:
        config_tree['routing'][protocol] = {}
    if 'routes' not in config_tree['routing'][protocol]:
        config_tree['routing'][protocol]['routes'] = []
    config_tree['routing'][protocol]['routes'].append(route_config)
    return config_tree
